import React, { useState, useEffect, useRef, useCallback } from 'react';
import { messagesAPI } from '../../utils/api';
import { useAuth } from '../../context/AuthContext';
import { useSocket } from '../../context/SocketContext';
import { format, isToday, isYesterday, isSameDay } from 'date-fns';
import toast from 'react-hot-toast';

/* ── tiny helpers ──────────────────────────────────────────── */
const COLORS = ['#4f7dff','#a855f7','#22c55e','#f59e0b','#ef4444','#06b6d4'];
function avatarColor(name=''){let h=0;for(const c of name)h=c.charCodeAt(0)+((h<<5)-h);return COLORS[Math.abs(h)%COLORS.length];}
function initials(name=''){return name.split(' ').map(w=>w[0]).join('').toUpperCase().slice(0,2);}
function fmtDate(d){const dt=new Date(d);if(isToday(dt))return'Today';if(isYesterday(dt))return'Yesterday';return format(dt,'MMMM d, yyyy');}
function fmtTime(d){return format(new Date(d),'HH:mm');}
function fmtSize(b){if(!b)return'';if(b<1024)return b+' B';if(b<1048576)return(b/1024).toFixed(1)+' KB';return(b/1048576).toFixed(1)+' MB';}
function fileIcon(mime){
  if(!mime)return'📄';
  if(mime.startsWith('image/'))return'🖼️';
  if(mime.startsWith('audio/'))return'🎵';
  if(mime.includes('pdf'))return'📕';
  if(mime.includes('sheet')||mime.includes('excel')||mime.includes('csv'))return'📊';
  if(mime.includes('word'))return'📝';
  if(mime.includes('zip'))return'🗜️';
  return'📎';
}

/* ── Task pill ─────────────────────────────────────────────── */
const TASK_META={
  initial_setup:{icon:'🚀',color:'#a855f7'},
  share_link:   {icon:'🔗',color:'#4f7dff'},
  pause_pid:    {icon:'⏸️',color:'#f59e0b'},
  raise_request:{icon:'📋',color:'#22c55e'},
  optimise:     {icon:'⚡',color:'#06b6d4'},
};
function TaskPill({taskRef,onTaskClick}){
  if(!taskRef)return null;
  const m=TASK_META[taskRef.task_type]||TASK_META.share_link;
  return(
    <span onClick={()=>onTaskClick?.(taskRef.task_id,taskRef.task_type)}
      style={{display:'inline-flex',alignItems:'center',gap:5,
        background:`${m.color}18`,border:`1px solid ${m.color}40`,
        borderRadius:20,padding:'2px 10px',cursor:'pointer',
        fontSize:11,color:m.color,fontWeight:600,marginTop:4,
        userSelect:'none',transition:'background .15s'}}
      onMouseEnter={e=>e.currentTarget.style.background=`${m.color}30`}
      onMouseLeave={e=>e.currentTarget.style.background=`${m.color}18`}
    >{m.icon} {taskRef.task_title} <span style={{fontSize:9,opacity:.6}}>→ open</span></span>
  );
}

/* ── Single bubble ─────────────────────────────────────────── */
function Bubble({msg,isOwn,showAvatar,onTaskClick}){
  // Task-notification system messages
  if(msg.message_type==='task_notification'||msg.message_type==='system'){
    return(
      <div style={{display:'flex',justifyContent:'center',padding:'6px 0'}}>
        <div style={{background:'rgba(79,125,255,.08)',border:'1px solid rgba(79,125,255,.2)',
          borderRadius:20,padding:'4px 14px',fontSize:12,color:'var(--text-secondary)',
          display:'inline-flex',alignItems:'center',gap:8,maxWidth:'80%',flexWrap:'wrap',justifyContent:'center'}}>
          <span>{msg.content}</span>
          {msg.task_ref&&<TaskPill taskRef={msg.task_ref} onTaskClick={onTaskClick}/>}
        </div>
      </div>
    );
  }

  // file_url is now ABSOLUTE from the backend (includes host+port) — use directly
  const fileUrl=msg.file_url||null;

  return(
    <div className={`message-row ${isOwn?'own':''}`}>
      {!isOwn&&(
        <div style={{width:32,height:32,borderRadius:'50%',
          background:`${avatarColor(msg.sender_name)}33`,color:avatarColor(msg.sender_name),
          display:'flex',alignItems:'center',justifyContent:'center',
          fontSize:11,fontWeight:700,flexShrink:0,opacity:showAvatar?1:0}}>
          {showAvatar?initials(msg.sender_name):''}
        </div>
      )}
      <div className="message-content">
        {showAvatar&&!isOwn&&(
          <div className="message-sender">{msg.sender_name}
            <span style={{fontSize:10,color:'var(--text-muted)',fontWeight:400,marginLeft:6,textTransform:'capitalize'}}>[{msg.sender_role}]</span>
          </div>
        )}
        {msg.reply_content&&(
          <div style={{background:'var(--bg-active)',borderLeft:'3px solid var(--accent)',borderRadius:6,padding:'4px 10px',marginBottom:4,fontSize:12,color:'var(--text-secondary)'}}>
            <strong>{msg.reply_sender_name}: </strong>{msg.reply_content?.slice(0,80)}{msg.reply_content?.length>80?'…':''}
          </div>
        )}

        {/* IMAGE */}
        {msg.message_type==='image'&&fileUrl?(
          <div style={{maxWidth:300}}>
            <img src={fileUrl} alt={msg.file_name}
              style={{maxWidth:'100%',maxHeight:260,borderRadius:10,cursor:'pointer',border:'1px solid var(--border)',display:'block'}}
              onClick={()=>window.open(fileUrl,'_blank')}
              onError={e=>e.target.style.display='none'}/>
          </div>

        /* AUDIO */
        ):msg.message_type==='audio'&&fileUrl?(
          <div className={`message-bubble ${isOwn?'sent':'received'}`} style={{padding:'8px 12px'}}>
            <audio controls style={{height:34,maxWidth:240}}><source src={fileUrl}/></audio>
          </div>

        /* FILE — anchor with download attr so browser saves it */
        ):fileUrl?(
          <a href={fileUrl} download={msg.file_name}
            style={{textDecoration:'none'}}
            onClick={e=>e.stopPropagation()}>
            <div style={{display:'flex',alignItems:'center',gap:10,padding:'10px 14px',
              background:'var(--bg-active)',border:'1px solid var(--border)',borderRadius:10,
              cursor:'pointer',maxWidth:300,transition:'border-color .15s'}}
              onMouseEnter={e=>e.currentTarget.style.borderColor='var(--accent)'}
              onMouseLeave={e=>e.currentTarget.style.borderColor='var(--border)'}>
              <span style={{fontSize:26}}>{fileIcon(msg.mime_type)}</span>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:13,fontWeight:600,color:'var(--text-primary)',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{msg.file_name}</div>
                <div style={{fontSize:11,color:'var(--text-muted)',marginTop:2}}>{fmtSize(msg.file_size)} · click to download</div>
              </div>
              <span style={{fontSize:22,color:'var(--accent)'}}>⬇</span>
            </div>
          </a>

        /* TEXT */
        ):(
          <div className={`message-bubble ${isOwn?'sent':'received'}`}>
            {msg.is_deleted?<em style={{opacity:.6}}>Message deleted</em>:msg.content}
          </div>
        )}

        {/* task pill below normal messages */}
        {msg.task_ref&&msg.message_type!=='task_notification'&&(
          <div><TaskPill taskRef={msg.task_ref} onTaskClick={onTaskClick}/></div>
        )}

        <div className="message-time">
          <span>{fmtTime(msg.sent_at)}</span>
          {isOwn&&<span style={{color:'var(--success)',marginLeft:4}}>✓✓</span>}
        </div>
      </div>
    </div>
  );
}

/* ── Main ChatMessages ──────────────────────────────────────── */
export default function ChatMessages({group,onTaskClick}){
  const {user}=useAuth();
  const {on,joinGroup,markSeen,sendTyping}=useSocket();

  const [messages,setMessages]=useState([]);
  const [loading,setLoading]=useState(true);
  const [page,setPage]=useState(1);
  const [hasMore,setHasMore]=useState(false);
  const [inputText,setInputText]=useState('');
  const [sending,setSending]=useState(false);
  const [replyTo,setReplyTo]=useState(null);
  const [typingUsers,setTypingUsers]=useState([]);
  const [isRecording,setIsRecording]=useState(false);
  const [showTaskPopup,setShowTaskPopup]=useState(false);

  const bottomRef =useRef(null);
  const fileRef   =useRef(null);
  const typingTmr =useRef(null);
  const mediaRec  =useRef(null);
  const audioChunks=useRef([]);

  // Store groupId as Number in a ref so stable callbacks can read it
  const groupIdRef=useRef(null);
  useEffect(()=>{groupIdRef.current=group?.id?Number(group.id):null;},[group?.id]);

  /* load */
  const load=useCallback(async(p=1)=>{
    if(!group)return;
    if(p===1)setLoading(true);
    try{
      const data=await messagesAPI.getMessages(group.id,p);
      if(p===1){
        setMessages(data.messages||[]);
        setTimeout(()=>bottomRef.current?.scrollIntoView({behavior:'instant'}),80);
      } else {
        setMessages(prev=>[...(data.messages||[]),...prev]);
      }
      setHasMore(data.hasMore);
      setPage(p);
    }catch(e){console.error(e);}
    setLoading(false);
  },[group]);// eslint-disable-line

  useEffect(()=>{
    if(!group)return;
    setMessages([]);setPage(1);
    load(1);
    joinGroup(group.id);
  },[group?.id]);// eslint-disable-line

  /* ── socket: new_message ──
     IMPORTANT: this callback must be STABLE (no changing deps).
     We access groupIdRef (a ref) instead of group.id directly. */
  const handleNewMsg=useCallback((msg)=>{
    if(Number(msg.group_id)!==groupIdRef.current)return;
    setMessages(prev=>{
      if(prev.some(m=>m.id===msg.id))return prev;
      return[...prev,msg];
    });
    // fire-and-forget — markSeen is stable (defined with useCallback in SocketContext)
    socketMarkSeen.current?.(msg.id,msg.group_id);
    setTimeout(()=>bottomRef.current?.scrollIntoView({behavior:'smooth'}),60);
  },[]);// NO deps — reads refs only

  // store markSeen in a ref so handleNewMsg can call it without being a dep
  const socketMarkSeen=useRef(markSeen);
  useEffect(()=>{socketMarkSeen.current=markSeen;},[markSeen]);

  const handleTypingEv=useCallback(({user_id,user_name,groupId,isTyping})=>{
    if(Number(groupId)!==groupIdRef.current)return;
    setTypingUsers(prev=>isTyping
      ?[...prev.filter(u=>u.id!==user_id),{id:user_id,name:user_name}]
      :prev.filter(u=>u.id!==user_id));
  },[]);

  useEffect(()=>{
    const u1=on('new_message',handleNewMsg);
    const u2=on('user_typing',handleTypingEv);
    return()=>{u1?.();u2?.();};
  },[on,handleNewMsg,handleTypingEv]);

  /* send text */
  const send=async()=>{
    if(!inputText.trim()||sending)return;
    const txt=inputText.trim();
    setInputText('');setSending(true);
    clearTimeout(typingTmr.current);sendTyping(group.id,false);
    try{
      const data=await messagesAPI.sendMessage(group.id,{content:txt,reply_to_id:replyTo?.id||null});
      setMessages(prev=>prev.some(m=>m.id===data.message.id)?prev:[...prev,data.message]);
      setReplyTo(null);
      bottomRef.current?.scrollIntoView({behavior:'smooth'});
    }catch{toast.error('Failed to send');setInputText(txt);}
    setSending(false);
  };

  const onKey=e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();send();}};
  const onInput=e=>{
    setInputText(e.target.value);
    sendTyping(group.id,true);
    clearTimeout(typingTmr.current);
    typingTmr.current=setTimeout(()=>sendTyping(group.id,false),2000);
  };
  {/* Task — first, before attach */}
<button className="btn-icon" onClick={()=>setShowTaskPopup(p=>!p)} title="Create task"
  style={{color:showTaskPopup?'var(--accent)':'inherit'}}>
  <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
    <path d="M9 11l3 3L22 4"/>
    <path d="M21 12v7a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h11"/>
  </svg>
</button>

  /* file upload */
  const uploadFile=async e=>{
    const file=e.target.files[0];if(!file)return;
    if(file.size>52428800){toast.error('Max 50 MB');return;}
    const fd=new FormData();fd.append('file',file);
    const tid=toast.loading(`Uploading ${file.name}…`);
    try{
      const data=await messagesAPI.uploadFile(group.id,fd);
      setMessages(prev=>prev.some(m=>m.id===data.message.id)?prev:[...prev,data.message]);
      bottomRef.current?.scrollIntoView({behavior:'smooth'});
      toast.success('Done!',{id:tid});
    }catch{toast.error('Upload failed',{id:tid});}
    e.target.value='';
  };

  /* voice recording */
  const startRec=async()=>{
    try{
      const stream=await navigator.mediaDevices.getUserMedia({audio:true});
      audioChunks.current=[];
      mediaRec.current=new MediaRecorder(stream);
      mediaRec.current.ondataavailable=e=>audioChunks.current.push(e.data);
      mediaRec.current.onstop=async()=>{
        const blob=new Blob(audioChunks.current,{type:'audio/webm'});
        const fd=new FormData();fd.append('file',blob,`voice_${Date.now()}.webm`);
        const tid=toast.loading('Sending voice…');
        try{
          const data=await messagesAPI.uploadFile(group.id,fd);
          setMessages(prev=>[...prev,data.message]);
          bottomRef.current?.scrollIntoView({behavior:'smooth'});
          toast.success('Sent!',{id:tid});
        }catch{toast.error('Failed',{id:tid});}
        stream.getTracks().forEach(t=>t.stop());
      };
      mediaRec.current.start();setIsRecording(true);
    }catch{toast.error('Mic denied');}
  };
  const stopRec=()=>{mediaRec.current?.stop();setIsRecording(false);};

  /* group messages */
  const grouped=messages.reduce((acc,msg,i)=>{
    const prev=messages[i-1];
    const showDate=!prev||!isSameDay(new Date(prev.sent_at),new Date(msg.sent_at));
    const showAvatar=!prev||prev.sender_id!==msg.sender_id||showDate;
    acc.push({...msg,showDate,showAvatar});
    return acc;
  },[]);

  if(!group)return(
    <div className="empty-state" style={{flex:1}}>
      <div className="empty-state-icon">💬</div><p>Select a group</p>
    </div>
  );

  return(
    <>
      <div className="messages-area">
        {hasMore&&(
          <div style={{textAlign:'center',paddingBottom:12}}>
            <button className="btn btn-secondary btn-sm" onClick={()=>load(page+1)}>Load older</button>
          </div>
        )}
        {loading?(
          <div className="empty-state"><p>Loading…</p></div>
        ):messages.length===0?(
          <div className="empty-state"><div className="empty-state-icon">🚀</div><p>Start the conversation!</p></div>
        ):grouped.map(msg=>(
          <React.Fragment key={msg.id}>
            {msg.showDate&&<div className="date-divider">{fmtDate(msg.sent_at)}</div>}
            <div onDoubleClick={()=>setReplyTo(msg)}>
              <Bubble msg={msg} isOwn={msg.sender_id===user?.id} showAvatar={msg.showAvatar} onTaskClick={onTaskClick}/>
            </div>
          </React.Fragment>
        ))}
        {typingUsers.length>0&&(
          <div className="message-row" style={{gap:10,paddingTop:4}}>
            <div style={{width:32}}/>
            <div>
              <div className="message-sender">{typingUsers.map(u=>u.name).join(', ')}</div>
              <div className="typing-indicator"><div className="typing-dot"/><div className="typing-dot"/><div className="typing-dot"/></div>
            </div>
          </div>
        )}
        <div ref={bottomRef}/>
      </div>

      <div className="input-area">


                {/* Task popup sits directly above the input bar, chat messages remain visible */}
                {showTaskPopup && (
                  <TaskQuickPopup
                    group={group}
                    onClose={() => setShowTaskPopup(false)}
                  />
                )}
        {replyTo&&(
          <div className="reply-preview">
            <span>↩ <strong>{replyTo.sender_name}:</strong> {replyTo.content?.slice(0,60)}</span>
            <button className="btn-icon" style={{padding:4}} onClick={()=>setReplyTo(null)}>✕</button>
          </div>
        )}
        {isRecording?(
          <div style={{display:'flex',alignItems:'center',gap:12,padding:'8px 12px',background:'rgba(239,68,68,.1)',border:'1px solid rgba(239,68,68,.3)',borderRadius:'var(--radius-xl)'}}>
            <span style={{fontSize:13,color:'#ef4444',fontWeight:600}}>🔴 Recording…</span>
            <button className="btn btn-danger btn-sm" onClick={stopRec}>Stop &amp; Send</button>
          </div>
        ):(
          <div className="input-container">
            <textarea className="message-input"
              placeholder={`Message ${group.group_name}…`}
              value={inputText} onChange={onInput} onKeyDown={onKey}
              rows={1} style={{height:'auto'}}
              onInput={e=>{e.target.style.height='auto';e.target.style.height=Math.min(e.target.scrollHeight,120)+'px';}}
            />
            <div className="input-actions">
              <input ref={fileRef} type="file" style={{display:'none'}} onChange={uploadFile}
                accept="image/*,audio/*,.pdf,.doc,.docx,.xls,.xlsx,.csv,.txt,.zip"/>
              <button className="btn-icon" onClick={()=>fileRef.current?.click()} title="Attach">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"/>
                </svg>
              </button>
              <button className="btn-icon" onClick={startRec} title="Voice">
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M12 1a3 3 0 00-3 3v8a3 3 0 006 0V4a3 3 0 00-3-3z"/>
                  <path d="M19 10v2a7 7 0 01-14 0v-2M12 19v4M8 23h8"/>
                </svg>
              </button>
              <button className="btn btn-primary" style={{padding:'8px 14px',borderRadius:'var(--radius-lg)'}}
                onClick={send} disabled={!inputText.trim()||sending}>
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
                  <line x1="22" y1="2" x2="11" y2="13"/>
                  <polygon points="22 2 15 22 11 13 2 9 22 2"/>
                </svg>
              </button>
            </div>
          </div>
        )}
      </div>
    </>
  );
}
